// =====================================================
// G777 Message Parser - Universal Format Handler
// =====================================================
// Handles data from: Evolution API, Baileys, Postman Tests
// =====================================================

const inputData = items[0]?.json;
console.log('📥 Raw Input:', JSON.stringify(inputData).substring(0, 500));

// Try multiple data paths (Evolution API sends in different formats)
let body = null;

// Path 1: Evolution API v2 format
if (inputData?.body?.data) {
  body = inputData.body.data;
  console.log('📍 Found data at: body.data');
}
// Path 2: Direct data object
else if (inputData?.data?.key) {
  body = inputData.data;
  console.log('📍 Found data at: data');
}
// Path 3: Body is the data itself
else if (inputData?.body?.key) {
  body = inputData.body;
  console.log('📍 Found data at: body');
}
// Path 4: Root level (Postman direct test)
else if (inputData?.key) {
  body = inputData;
  console.log('📍 Found data at: root');
}
// Path 5: Baileys format
else if (inputData?.body?.message) {
  body = inputData.body;
  console.log('📍 Found data at: body (Baileys)');
}

if (!body) {
  console.log('❌ No valid data structure found');
  console.log('Available keys:', Object.keys(inputData || {}));
  return [];
}

// Extract message text
let message = '';
if (body.message) {
  message = body.message.conversation || 
            body.message.extendedTextMessage?.text || 
            body.message.imageMessage?.caption ||
            body.message.text ||
            '';
}

// Extract phone from remoteJid
let phone = '';
let remoteJid = '';
if (body.key && body.key.remoteJid) {
  remoteJid = body.key.remoteJid;
  phone = remoteJid.replace('@s.whatsapp.net', '').replace('@c.us', '');
}

// Check if from bot
const fromMe = body.key?.fromMe || false;

// Get customer name
const customerName = body.pushName || body.notifyName || 'عميل';

console.log('📊 Extracted Data:');
console.log('   Phone:', phone);
console.log('   Message:', message.substring(0, 50));
console.log('   FromMe:', fromMe);
console.log('   CustomerName:', customerName);

// Validation - Skip if:
// 1. No phone number
// 2. No message
// 3. From bot itself
if (!phone || !message || fromMe) {
  console.log('⏭️ Skipping: phone=' + phone + ', message=' + (message ? 'exists' : 'empty') + ', fromMe=' + fromMe);
  return [];
}

// Return clean data
return [{
  json: {
    phone: phone,
    message: message,
    sessionId: phone,
    chatId: remoteJid,
    customerName: customerName,
    timestamp: new Date().toISOString()
  }
}];
